import{_ as t,o as r,c as s,aj as o}from"./chunks/framework.DEEoir6m.js";const h=JSON.parse('{"title":"Communaute","description":"Rejoindre la communaute GISPulse — GitHub, contributions, roadmap, contact et support.","frontmatter":{"title":"Communaute","description":"Rejoindre la communaute GISPulse — GitHub, contributions, roadmap, contact et support."},"headers":[],"relativePath":"community.md","filePath":"community.md"}'),a={name:"community.md"};function i(n,e,l,d,u,p){return r(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="communaute" tabindex="-1">Communaute <a class="header-anchor" href="#communaute" aria-label="Permalink to &quot;Communaute&quot;">​</a></h1><p>GISPulse est un projet open-source construit par et pour les professionnels du geospatial. Rejoignez la communaute.</p><hr><h2 id="liens-principaux" tabindex="-1">Liens principaux <a class="header-anchor" href="#liens-principaux" aria-label="Permalink to &quot;Liens principaux&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ressource</th><th>Lien</th></tr></thead><tbody><tr><td>Code source</td><td><a href="https://github.com/gispulse/gispulse" target="_blank" rel="noreferrer">github.com/gispulse/gispulse</a></td></tr><tr><td>Discussions</td><td><a href="https://github.com/gispulse/gispulse/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></td></tr><tr><td>Issues &amp; bugs</td><td><a href="https://github.com/gispulse/gispulse/issues" target="_blank" rel="noreferrer">GitHub Issues</a></td></tr><tr><td>Documentation</td><td><a href="https://gispulse.dev" target="_blank" rel="noreferrer">gispulse.dev</a></td></tr><tr><td>Blog</td><td><a href="/gispulse/blog/gispulse-vs-fme">gispulse.dev/blog</a></td></tr><tr><td>Changelog</td><td><a href="/gispulse/changelog">gispulse.dev/changelog</a></td></tr><tr><td>Contact</td><td><a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a></td></tr></tbody></table><hr><h2 id="participer" tabindex="-1">Participer <a class="header-anchor" href="#participer" aria-label="Permalink to &quot;Participer&quot;">​</a></h2><h3 id="reporter-un-bug" tabindex="-1">Reporter un bug <a class="header-anchor" href="#reporter-un-bug" aria-label="Permalink to &quot;Reporter un bug&quot;">​</a></h3><p>Ouvrez une <a href="https://github.com/gispulse/gispulse/issues" target="_blank" rel="noreferrer">issue</a> avec :</p><ol><li>Version de GISPulse (<code>gispulse --version</code>)</li><li>Etapes de reproduction</li><li>Comportement attendu vs observe</li><li>Logs complets (<code>--verbose</code>)</li></ol><h3 id="proposer-une-fonctionnalite" tabindex="-1">Proposer une fonctionnalite <a class="header-anchor" href="#proposer-une-fonctionnalite" aria-label="Permalink to &quot;Proposer une fonctionnalite&quot;">​</a></h3><p>Ouvrez une <a href="https://github.com/gispulse/gispulse/discussions" target="_blank" rel="noreferrer">discussion</a> dans la categorie &quot;Ideas&quot;. Decrivez :</p><ul><li>Le cas d&#39;usage concret</li><li>Le comportement souhaite</li><li>Les alternatives envisagees</li></ul><h3 id="contribuer-du-code" tabindex="-1">Contribuer du code <a class="header-anchor" href="#contribuer-du-code" aria-label="Permalink to &quot;Contribuer du code&quot;">​</a></h3><p>Le guide complet est disponible ici : <a href="/gispulse/contributing">Contribuer a GISPulse</a>.</p><p>En resume :</p><ol><li>Forkez le depot</li><li>Creez une branche (<code>feat/</code>, <code>fix/</code>, <code>docs/</code>)</li><li>Ecrivez du code avec tests et type hints</li><li>Ouvrez une pull request vers <code>main</code></li></ol><div class="tip custom-block"><p class="custom-block-title">Premier contribution ?</p><p>Cherchez les issues etiquetees <a href="https://github.com/gispulse/gispulse/issues?q=label%3A%22good+first+issue%22" target="_blank" rel="noreferrer"><code>good first issue</code></a> — elles sont concues pour accueillir les nouveaux contributeurs.</p></div><hr><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h2><p>GISPulse suit une roadmap publique orientee par les besoins terrain des professionnels GIS.</p><h3 id="vision-a-long-terme" tabindex="-1">Vision a long terme <a class="header-anchor" href="#vision-a-long-terme" aria-label="Permalink to &quot;Vision a long terme&quot;">​</a></h3><p>Devenir le moteur geospatial de reference pour les pipelines declaratifs — le <strong>dbt du geospatial</strong>.</p><h3 id="axes-en-cours" tabindex="-1">Axes en cours <a class="header-anchor" href="#axes-en-cours" aria-label="Permalink to &quot;Axes en cours&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Axe</th><th>Statut</th><th>Horizon</th></tr></thead><tbody><tr><td>Moteur DuckDB + PostGIS + GPKG portable</td><td>Livre</td><td>v1.0</td></tr><tr><td>117 capabilities (vecteur, attributs, classification, stats, topologie, 3D pointcloud, raster, reseau, PostGIS SQL)</td><td>Livre</td><td>v1.1</td></tr><tr><td>CLI / API REST / SDK Python</td><td>Livre</td><td>v1.0</td></tr><tr><td>Plugin QGIS / Add-in ArcGIS / Desktop Tauri</td><td>Livre</td><td>v1.0</td></tr><tr><td>Templates de pipelines metier (21 presets)</td><td>Livre</td><td>v1.0</td></tr><tr><td>6 scenarios playground interactifs</td><td>Livre</td><td>v1.1</td></tr><tr><td>RBAC, SSO (OIDC/SAML), audit log, S3 storage</td><td>Livre</td><td>v1.0</td></tr><tr><td>Visual node editor</td><td>Beta</td><td>v1.2</td></tr><tr><td>Ingestion WFS / OGC API Features</td><td>Planifie</td><td>v1.3</td></tr><tr><td>Exposition MVT / STAC</td><td>Planifie</td><td>v1.3</td></tr><tr><td>Marketplace de capabilities</td><td>Planifie</td><td>v2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La roadmap est indicative. Les priorites evoluent selon les retours de la communaute et les besoins des utilisateurs Pro/Team/Enterprise.</p></div><hr><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Canal</th><th>Delai</th></tr></thead><tbody><tr><td>Community</td><td>GitHub Discussions / Issues</td><td>Communaute (best effort)</td></tr><tr><td>Pro</td><td>GitHub Discussions / Issues</td><td>Communaute (best effort)</td></tr><tr><td>Team</td><td>Support prioritaire par email</td><td>48h garanti</td></tr><tr><td>Enterprise</td><td>Support dedie</td><td>SLA 4h garanti</td></tr></tbody></table><p>Pour le support commercial : <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a>.</p><hr><h2 id="sponsors-soutien" tabindex="-1">Sponsors &amp; soutien <a class="header-anchor" href="#sponsors-soutien" aria-label="Permalink to &quot;Sponsors &amp; soutien&quot;">​</a></h2><p>GISPulse est un projet independant. Si vous utilisez GISPulse en production et souhaitez soutenir son developpement :</p><ul><li><strong>Tier Pro/Team/Enterprise</strong> : votre abonnement finance directement le developpement</li><li><strong>Sponsor GitHub</strong> : <a href="https://github.com/sponsors/gispulse" target="_blank" rel="noreferrer">Sponsoriser sur GitHub</a></li><li><strong>Contribution code</strong> : chaque PR compte</li><li><strong>Bouche-a-oreille</strong> : parlez de GISPulse a vos collegues GIS</li></ul><div class="tip custom-block"><p class="custom-block-title">Organisations publiques</p><p>Nous proposons des tarifs adaptes pour les collectivites territoriales, EPCI, syndicats mixtes et organismes de recherche. Contactez <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a>.</p></div><hr><h2 id="regles-de-la-communaute" tabindex="-1">Regles de la communaute <a class="header-anchor" href="#regles-de-la-communaute" aria-label="Permalink to &quot;Regles de la communaute&quot;">​</a></h2><p>Le projet suit le <a href="https://www.contributor-covenant.org/version/2/1/code_of_conduct/" target="_blank" rel="noreferrer">Contributor Covenant v2.1</a>. Les principes fondamentaux :</p><ul><li><strong>Respect</strong> : traitez chaque membre avec courtoisie</li><li><strong>Constructivite</strong> : critiquez les idees, pas les personnes</li><li><strong>Inclusion</strong> : le geospatial est un domaine vaste — accueillez les profils divers</li><li><strong>Transparence</strong> : les decisions techniques sont documentees publiquement</li></ul><p>Les violations peuvent etre reportees a <a href="mailto:conduct@gispulse.dev" target="_blank" rel="noreferrer">conduct@gispulse.dev</a>.</p><hr><h2 id="a-propos" tabindex="-1">A propos <a class="header-anchor" href="#a-propos" aria-label="Permalink to &quot;A propos&quot;">​</a></h2><p>GISPulse est ne du constat que les professionnels GIS passent trop de temps a re-ecrire les memes traitements spatiaux dans des scripts fragiles. Le projet propose une alternative : des regles declaratives, versionnables, portables et reproductibles.</p><p>Le coeur du moteur est et restera open-source sous licence AGPL-3.0.</p>',44)])])}const m=t(a,[["render",i]]);export{h as __pageData,m as default};
